const logs: LogEntry[] = [];
let minLevel: LogLevel = "info";
let verboseMode = false;
let sessionId = "";

function formatTimestamp(): string {
  return new Date().toISOString().split("T")[1].slice(0, -1);
}

function shouldLog(level: LogLevel): boolean {
  const levels: Record<LogLevel, number> = { debug: 0, info: 1, warn: 2, error: 3 };
  return levels[level] >= levels[minLevel];
}

function getSessionId(): string {
  if (!sessionId) {
    sessionId = `lee-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
  }
  return sessionId;
}

export function setLogLevel(level: LogLevel): void {
  const levels: Record<LogLevel, number> = { debug: 0, info: 1, warn: 2, error: 3 };
  minLevel = level;
}

export function setVerboseMode(enabled: boolean): void {
  verboseMode = enabled;
  if (verboseMode) {
    setLogLevel("debug");
  }
}

export function isVerboseMode(): boolean {
  return verboseMode;
}

export function log(level: LogLevel, message: string, data?: unknown): void {
  if (!shouldLog(level)) return;

  const entry: LogEntry = {
    timestamp: formatTimestamp(),
    level,
    message,
    data,
  };

  logs.push(entry);

  const prefix = {
    debug: "🔍",
    info: "ℹ️",
    warn: "⚠️",
    error: "❌",
  }[level];

  console.log(`${formatTimestamp()} ${prefix} ${message}`, data ? JSON.stringify(data).slice(0, 200) : "");
}

export function debug(message: string, data?: unknown): void {
  log("debug", message, data);
}

export function info(message: string, data?: unknown): void {
  log("info", message, data);
}

export function warn(message: string, data?: unknown): void {
  log("warn", message, data);
}

export function error(message: string, data?: unknown): void {
  log("error", message, data);
}

export function getLogs(): LogEntry[] {
  return [...logs];
}

export function clearLogs(): void {
  logs.length = 0;
}

export function saveLogs(filename: string = "lee-code.log"): string {
  const content = logs.map(l => 
    `${l.timestamp} [${l.level.toUpperCase()}] ${l.message}${l.data ? " " + JSON.stringify(l.data) : ""}`
  ).join("\n");

  require("fs").appendFileSync(filename, content + "\n", "utf-8");
  return filename;
}

